"""Render every living unit of the paper to its own generated file under
paper/live/. The skeleton WC2026_paper.tex carries only permanent \\input lines
and is never written by the pipeline; skeleton_hash + data/skeleton_sha256.txt
prove it byte-identical on every run. Pure renderers: context in, tex out."""
import hashlib
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parent))
import render_evolution as rev
import poisson_model as pm
import draft_sections as _ds

HEADER = "% GENERATED by scripts/render_live.py — do not edit by hand.\n"


def skeleton_hash(tex):
    return hashlib.sha256(tex.encode()).hexdigest()


def write_unit(live_dir, name, content):
    Path(live_dir).mkdir(parents=True, exist_ok=True)
    (Path(live_dir) / f"{name}.tex").write_text(HEADER + content + "\n",
                                                encoding="utf-8")


def validate_labels(name, content, required):
    """Raise ValueError if any required \\label{tag} is absent from content."""
    for label in required:
        if f"\\label{{{label}}}" not in content:
            raise ValueError(
                f"render_live: {name}.tex missing \\label{{{label}}} — "
                f"add it to the generator or the prompt template")


def outcome_probs(lh, la):
    """Normalized P(H/D/A) for display (poisson_model's raw triple loses the
    truncated mass beyond MAX_G goals)."""
    ph, pd, pa = pm.outcome_probs(lh, la)
    s = ph + pd + pa
    return ph / s, pd / s, pa / s


def _pct(x):
    return f"{100 * x:.1f}"


